// ===========================================
// W2 Command Router
// ===========================================
// Validates API key, extracts action, routes to handler.

const body = $input.first().json.body || $input.first().json;
const action = (body.action || '').toLowerCase().trim();
const target = body.target || null;
const params = body.params || {};

// Valid actions
const validActions = [
  'today', 'complete', 'cancel', 'defer', 'restore', 'edit',
  'add', 'regen', 'brief', 'stats', 'deferred', 'preview',
  'weekly', 'help', 'ping'
];

if (!validActions.includes(action)) {
  return [{
    json: {
      response_type: 'error',
      message: `\u274C [UNKNOWN_COMMAND] Unknown command '${action}'. Type /help for available commands.`,
      data: { error_code: 'UNKNOWN_COMMAND' },
      suggestions: ['Type /help for available commands'],
      awaiting_input: false,
      _route: 'error'
    }
  }];
}

return [{
  json: {
    action,
    target,
    params,
    _route: action
  }
}];

// ===========================================
// /today — Quest Board View
// ===========================================
// Queries Daily Quests project for today's issues,
// formats response grouped by state buckets.

const config = {
  base_url: $env.PULSE_PLANE_BASE_URL,
  workspace_slug: $env.PULSE_PLANE_WORKSPACE_SLUG,
  api_key: $env.PULSE_PLANE_API_KEY,
  daily_quest_project_id: $env.PULSE_DAILY_QUEST_PROJECT_ID,
};

const basePath = `${config.base_url}/api/v1/workspaces/${config.workspace_slug}`;
const headers = { 'X-API-Key': config.api_key, 'Content-Type': 'application/json' };
const tz = $env.PULSE_USER_TIMEZONE || 'Asia/Seoul';

// --- Retry helper ---
const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
const MAX_RETRIES = 3;
const RETRY_MS = 5000;
const withRetry = async (fn, ctx) => {
  for (let i = 1; i <= MAX_RETRIES; i++) {
    try { return await fn(); } catch (e) {
      console.log(`[RETRY] ${ctx} attempt ${i}/${MAX_RETRIES}: ${e.message}`);
      if (i === MAX_RETRIES) throw e;
      await sleep(RETRY_MS);
    }
  }
};

const apiGet = async (path) => {
  const res = await fetch(`${basePath}${path}`, { method: 'GET', headers });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json();
};

// --- Meta extractor ---
const decodeEntities = (s) => s.replace(/&quot;/g, '"').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&#39;/g, "'").replace(/&apos;/g, "'");
const extractMeta = (html) => {
  if (!html) return null;
  try {
    let m = html.match(/<pre><code\s+class="language-pulse-meta">([\s\S]*?)<\/code><\/pre>/);
    if (m) return JSON.parse(decodeEntities(m[1].trim()));
    m = html.match(/<pre><code>([\s\S]*?)<\/code><\/pre>/);
    if (m) { const c = decodeEntities(m[1].trim()); if (c.includes('"schema_version"')) return JSON.parse(c); }
    m = html.match(/```pulse-meta\s*\n([\s\S]*?)\n\s*```/);
    if (m) return JSON.parse(m[1].trim());
  } catch (e) { return null; }
  return null;
};

// --- Priority ---
const PRIORITY_EMOJI = { 4: '\uD83D\uDD34', 3: '\uD83D\uDFE0', 2: '\uD83D\uDFE1', 1: '\uD83D\uDFE2', 0: '\uD83D\uDFE2' };
const PRIORITY_NAME = { 4: 'urgent', 3: 'high', 2: 'medium', 1: 'low', 0: 'none' };
const formatDuration = (min) => {
  if (!min) return '';
  if (min >= 60) { const h = Math.floor(min / 60); const m = min % 60; return m > 0 ? `${h}h${m}min` : `${h}h`; }
  return `${min}min`;
};

// --- State config ---
const STATE_ORDER = ['To-Do', 'In Progress', 'Deferred', 'Done', 'Canceled'];
const STATE_EMOJI = { 'To-Do': '\uD83D\uDCCB', 'In Progress': '\u23F3', 'Deferred': '\u23F8\uFE0F', 'Done': '\u2705', 'Canceled': '\uD83D\uDEAB' };

try {
  const todayStr = new Date().toLocaleDateString('en-CA', { timeZone: tz });
  const dayName = new Date().toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' });

  // Fetch today's quests
  const result = await withRetry(
    () => apiGet(`/projects/${config.daily_quest_project_id}/issues/?per_page=100&expand=labels,state&target_date=${todayStr}`),
    'Fetch today quests'
  );
  const quests = result.results || result || [];

  // Group by state
  const grouped = {};
  for (const s of STATE_ORDER) grouped[s] = [];

  for (const q of quests) {
    const stateName = q.state_detail?.name || 'To-Do';
    if (!grouped[stateName]) grouped[stateName] = [];
    grouped[stateName].push(q);
  }

  // Check degraded mode from project description
  let degradedMode = false;
  try {
    const projRes = await withRetry(
      () => apiGet(`/projects/${config.daily_quest_project_id}/`),
      'Fetch project status'
    );
    const projDesc = projRes.description_html || '';
    const statusMatch = projDesc.match(/<pre><code\s+class="language-pulse-status">([\s\S]*?)<\/code><\/pre>/);
    if (statusMatch) {
      const status = JSON.parse(statusMatch[1]);
      if (status.last_run === todayStr && status.degraded_mode) {
        degradedMode = true;
      }
    }
  } catch (e) {
    console.log(`[WARN] Could not read project status: ${e.message}`);
  }

  // Format header
  let header = `\uD83D\uDCCB ${todayStr} (${dayName}) Today's Quests`;
  if (degradedMode) {
    header = `\u26A0\uFE0F [DEGRADED_MODE] AI features temporarily unavailable. Routine-based quests generated normally.\n\n${header}`;
  }

  // Build body
  let body = '';
  for (const state of STATE_ORDER) {
    const items = grouped[state];
    if (!items || items.length === 0) continue;
    const emoji = STATE_EMOJI[state] || '';
    body += `\n${emoji} **${state}** (${items.length})\n`;
    for (const q of items) {
      const pEmoji = PRIORITY_EMOJI[q.priority] || '\uD83D\uDFE1';
      const meta = extractMeta(q.description_html);
      const time = meta?.routine_time || '--:--';
      const dur = meta?.routine_duration_min ? formatDuration(meta.routine_duration_min) : '';
      const deferSuffix = meta?.defer_count > 0 ? ` (deferred x${meta.defer_count})` : '';
      body += `  ${pEmoji} ${q.name} \u2014 ${time}${dur ? ` (${dur})` : ''}${deferSuffix}\n`;
    }
  }

  if (quests.length === 0) {
    body = '\n_No quests for today. Enjoy your free day!_\n';
  }

  return [{
    json: {
      response_type: 'quest_board',
      message: `${header}\n${body}`,
      data: {
        total: quests.length,
        by_state: Object.fromEntries(STATE_ORDER.map((s) => [s, (grouped[s] || []).length])),
      },
      suggestions: [],
      awaiting_input: false,
    }
  }];
} catch (e) {
  return [{
    json: {
      response_type: 'error',
      message: `\u274C [W2-TODAY] [PLANE_API_ERROR] Failed to fetch today's quests: ${e.message}. Please check Plane.so API configuration.`,
      data: { error_code: 'PLANE_API_ERROR' },
      suggestions: ['Check n8n execution logs', 'Verify Plane.so connectivity'],
      awaiting_input: false,
    }
  }];
}

// Ping handler for connectivity test
return [{
  json: {
    response_type: 'info',
    message: 'pong',
    data: { status: 'ok', timestamp: new Date().toISOString() },
    suggestions: [],
    awaiting_input: false,
  }
}];

